+import type { Command } from "commander";
+import { callGateway } from "../gateway/call.js";
+
+export type GatewayRpcOpts = {
+  url?: string;
+  token?: string;
+  timeout?: string;
+  expectFinal?: boolean;
+};
+
+export function addGatewayClientOptions(cmd: Command) {
+  return cmd
